import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";

function ClientDashboard() {
  const [user, setUser] = useState(null);
  const [stats, setStats] = useState({
    inProgress: 0,
    newProposals: 0,
    totalProjects: 0
  });
  const [projects, setProjects] = useState([]);
  const [proposals, setProposals] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const token = localStorage.getItem("access");
    if (!token) {
      navigate("/");
    } else {
      fetchDashboardData();
    }
  }, [navigate]);

  const fetchDashboardData = async () => {
    try {
      const token = localStorage.getItem('access');

      // Get current user info
      const userRes = await axios.get('http://127.0.0.1:8000/api/users/me/', {
        headers: { Authorization: `Bearer ${token}` }
      });

      setUser(userRes.data);

      // Fetch all projects
      const projectsRes = await axios.get('http://127.0.0.1:8000/api/projects/', {
        headers: { Authorization: `Bearer ${token}` }
      });

      // Fetch all proposals
      const proposalsRes = await axios.get('http://127.0.0.1:8000/api/proposals/', {
        headers: { Authorization: `Bearer ${token}` }
      });

      // Filter client's own projects
      const clientProjects = projectsRes.data.filter(p => p.client === userRes.data.id);

      // Filter proposals for client's projects
      const clientProjectIds = clientProjects.map(p => p.id);
      const clientProposals = proposalsRes.data.filter(p => clientProjectIds.includes(p.project));
      const newProps = clientProposals.filter(p => p.status === 'pending');

      setProjects(clientProjects.slice(0, 2));
      setProposals(newProps.slice(0, 3));

      setStats({
        inProgress: clientProjects.filter(p => p.status === 'in_progress').length,
        newProposals: newProps.length,
        totalProjects: clientProjects.length
      });

      setLoading(false);
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
      setLoading(false);
    }
  };

  const handleAcceptProposal = async (proposalId) => {
    try {
      const token = localStorage.getItem('access');
      await axios.patch(`http://127.0.0.1:8000/api/proposals/${proposalId}/`,
        { status: 'accepted' },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      alert('Proposal accepted!');
      fetchDashboardData();
    } catch (error) {
      console.error('Error accepting proposal:', error);
      alert('Failed to accept proposal');
    }
  };

  const handleRejectProposal = async (proposalId) => {
    try {
      const token = localStorage.getItem('access');
      await axios.patch(`http://127.0.0.1:8000/api/proposals/${proposalId}/`,
        { status: 'rejected' },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      alert('Proposal rejected');
      fetchDashboardData();
    } catch (error) {
      console.error('Error rejecting proposal:', error);
      alert('Failed to reject proposal');
    }
  };

  const handleLogout = () => {
    localStorage.clear();
    navigate('/');
  };

  if (loading) return <div className="loading">Loading dashboard...</div>;

  return (
    <div className="dashboard-container">
      {/* Top Bar */}
      <div className="top-bar">
        <div className="logo">🔷 TalentLink</div>
        <div className="user-menu">
          <span className="username">👤 {user?.username || 'Client'}</span>
          <button onClick={() => navigate('/profile')} className="profile-btn">Edit Profile</button>
          <button onClick={handleLogout} className="logout-btn">Logout</button>
        </div>
      </div>

      {/* Welcome Section */}
      <div className="welcome-section">
        <h2>👋 Welcome back, {user?.username || 'Client'}!</h2>
        <span className="date">{new Date().toLocaleDateString()}</span>
      </div>

      {/* Stats Cards */}
      <div className="stats-grid">
        <div className="stat-card" onClick={() => navigate('/projects?status=in_progress')}>
          <span className="stat-label">📋 In Progress Projects</span>
          <span className="stat-value">{stats.inProgress}</span>
          {stats.inProgress === 0 && <span className="stat-hint">No active projects</span>}
        </div>
        <div className="stat-card" onClick={() => navigate('/proposals?status=pending')}>
          <span className="stat-label">📨 New Proposals</span>
          <span className="stat-value">{stats.newProposals}</span>
          {stats.newProposals === 0 && <span className="stat-hint">No new proposals</span>}
        </div>
        <div className="stat-card" onClick={() => navigate('/projects')}>
          <span className="stat-label">✅ Total Projects</span>
          <span className="stat-value">{stats.totalProjects}</span>
        </div>
      </div>

      {/* Post New Project Button */}
      <button className="post-project-btn" onClick={() => navigate('/projects/create')}>
        ➕ POST NEW PROJECT
      </button>

      {/* My Projects Section */}
      <div className="section-header">
        <h3>📋 MY PROJECTS</h3>
        <button className="view-all" onClick={() => navigate('/projects')}>View All →</button>
      </div>

      {projects.length > 0 ? (
        projects.map(project => (
          <div key={project.id} className="project-item">
            <div className="project-info">
              <strong>{project.title}</strong>
              <div className="project-meta">
                📅 {new Date(project.created_at).toLocaleDateString()} | 💰 ₹{project.budget_min}-{project.budget_max}
              </div>
            </div>
            <div className="project-actions">
              <button onClick={() => navigate(`/projects/${project.id}`)}>👁 View</button>
              <button onClick={() => navigate(`/projects/${project.id}/edit`)}>✏️ Edit</button>
              <button onClick={() => navigate(`/projects/${project.id}/proposals`)}>📋 Proposals</button>
            </div>
          </div>
        ))
      ) : (
        <p>No projects yet.</p>
      )}

      {/* Proposals Section */}
      <div className="section-header">
        <h3>📨 NEW PROPOSALS {stats.newProposals > 0 && `(${stats.newProposals})`}</h3>
        {stats.newProposals > 0 && (
          <button className="view-all" onClick={() => navigate('/proposals')}>View All →</button>
        )}
      </div>

      {proposals.length > 0 ? (
        proposals.map(proposal => (
          <div key={proposal.id} className="proposal-item">
            <div className="proposal-info">
              <strong>👤 {proposal.freelancer_name}</strong>
              <div>📝 {proposal.project_title}</div>
              <div className="proposal-meta">💰 ₹{proposal.bid_amount} | ⏱️ {proposal.estimated_days} days</div>
            </div>
            <div className="proposal-actions">
              <button className="accept-btn" onClick={() => handleAcceptProposal(proposal.id)}>✅ Accept</button>
              <button className="reject-btn" onClick={() => handleRejectProposal(proposal.id)}>❌ Reject</button>
              <button onClick={() => navigate(`/freelancer/${proposal.freelancer}`)}>👤 Profile</button>
            </div>
          </div>
        ))
      ) : (
        <p>No proposals yet.</p>
      )}
    </div>
  );
}

export default ClientDashboard;
